-- {"operators": "FULL_OUTER_JOIN,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": true, "tables": "OORDER,NEW_ORDER", "ducklake": true}
WITH ordered AS (SELECT O_W_ID AS w, O_ID AS id FROM dl.OORDER), new_list AS (SELECT NO_W_ID AS w, NO_O_ID AS id FROM dl.NEW_ORDER) SELECT COALESCE(o.w, n.w) AS w, COALESCE(o.id, n.id) AS id, CASE WHEN o.id IS NOT NULL AND n.id IS NOT NULL THEN 'both' WHEN o.id IS NOT NULL THEN 'only_order' ELSE 'only_new' END AS status FROM ordered o FULL OUTER JOIN new_list n ON o.w = n.w AND o.id = n.id;
